package Lec4;

public class Data_Type_Demo3 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		char ch = 'a';
		System.out.println((int) (ch));
		ch++;// ch = (char)(ch+1)
		System.out.println(ch);
		int i = 5;
		i++;// i = (int)(i+1)
		ch += 1;// ch = (char)(ch+1)
		System.out.println(ch);
		i += 1;// i = (int)(i+1)
	//	ch = ch + 1;// Error

	}

}
